#!/usr/bin/env dotnet
#:property InvariantGlobalization=false

// Find the earliest Friday the 13th in the proleptic Gregorian calendar (starting 0001-01-01)
// and count all Friday the 13ths in a full 400-year cycle.

// The Gregorian calendar repeats every 400 years exactly.
DateTime earliest = DateTime.MaxValue;
int count = 0;

for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var date = new DateTime(year, month, 13);
        if (date.DayOfWeek == DayOfWeek.Friday)
        {
            count++;
            if (date < earliest)
                earliest = date;
        }
    }
}

Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd}");
Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine();

// Bonus: show the first few
Console.WriteLine("First 10 Friday the 13ths:");
int shown = 0;
for (int year = 1; year <= 400 && shown < 10; year++)
{
    for (int month = 1; month <= 12 && shown < 10; month++)
    {
        var date = new DateTime(year, month, 13);
        if (date.DayOfWeek == DayOfWeek.Friday)
        {
            Console.WriteLine($"  {date:yyyy-MM-dd}");
            shown++;
        }
    }
}

